    <div class="hdr"><div class="hl"><div>THERMOTECH</div><div style="font-size:9px;font-weight:400;margin-top:2px">E &amp; P Ltd</div></div><div class="hm"><h1>Daily Activity Report</h1><div style="font-size:9px;color:#666;margin-top:3px">TEPL/IMS/F/027 | Thermotech Engineering and Projects Ltd</div></div><div class="hr"><div style="font-size:8px;font-weight:700;color:#546e7a;text-transform:uppercase;margin-bottom:3px">Date</div><div style="font-size:13px;font-weight:600">${f.date}</div><div style="font-size:8px;font-weight:700;color:#546e7a;text-transform:uppercase;margin:5px 0 2px">Week No.</div><div style="font-size:13px;font-weight:600">${f.week}</div></div></div>
